const data = $input.item.json.data;
let successCount = 0;
let failedSources = [];
for (const item of data) {
  if (item.valid === true) {
    successCount++;
  } else {
    failedSources.push(item.source || "unknown");
  }
}
return {
  json: {
    data: data,
    governance: {
      timestamp: new Date().toISOString(),
      sourcesSucceeded: successCount,
      sourcesFailedList: failedSources.join(", "),
      workflowVersion: "2.0.0"
    }
  }
};

