parameters.jsCode:
const output = $input.item.json.output || $input.item.json;
if (!output || typeof output !== 'object') {
  return { json: { output: { intro: "⚠️ Newsletter generation encountered a technical issue. Full content will be available next week." } } };
}
const intro = output.intro || output.text || "";
if (typeof intro !== 'string' || intro.trim().length === 0) {
  return { json: { output: { intro: "⚠️ The AI produced an empty response. Please check the logs." } } };
}
return { json: { output } };

