parameters.jsCode:
const item = $input.item.json;
const qaOutput = item.output || item;
const correctedIntro = qaOutput.corrected_intro || "⚠️ QA processing failed. Please check logs.";
const governance = $node["Count & Governance"].json.governance;
const isFallback = item._fallback === true;
if (isFallback) {
  governance.fallbackTriggered = true;
} else {
  governance.fallbackTriggered = false;
}
return {
  json: {
    intro: correctedIntro,
    parting_word: qaOutput.parting_word || "Keep learning, keep growing.",
    governance: governance,
    qa_passed: qaOutput.passed,
    qa_issues: qaOutput.issues || []
  }
};

